mapper.select:
SELECT c.id, c.content, c.user_id, c.target_type, c.target_id, c.parent_id, c.status, c.create_time, c.update_time, c.rating, u.name as user_name, u.avatar as user_avatar, u.role as user_role, (SELECT COUNT(*) FROM comment WHERE parent_id = c.id AND status = 0) as reply_count FROM comment c LEFT JOIN user u ON c.user_id = u.id WHERE c.status = 0
AND c.target_type = #{targetType}
AND c.target_id = #{targetId}
ORDER BY c.create_time DESC

SELECT c.id, c.content, c.user_id, c.target_type, c.target_id, c.parent_id, c.status, c.create_time, c.update_time, c.rating, u.name as user_name, u.avatar as user_avatar, u.role as user_role, (SELECT COUNT(*) FROM comment WHERE parent_id = c.id AND status = 0) as reply_count FROM comment c LEFT JOIN user u ON c.user_id = u.id WHERE c.status = 0 AND c.rating IS NOT NULL
AND c.target_type = #{targetType}
AND c.rating = #{rating}
AND c.target_type IN ('activity', 'service_item') ORDER BY c.create_time DESC
